@ARTICLE{10.1016/j.scib.2024.06.016,
	author = {Chen L and Kang Z and Shen J and Zhao R and Miao Y and Zhang L and Zheng Z and Zhang Z and Liu N and Wang C and Fang H and Zhou J and Wang Y and Liu Z and Yang Y and Chen Q},
	title = {An emerging antibacterial nanovaccine for enhanced chemotherapy by selectively eliminating tumor-colonizing bacteria.},
	journal = {Sci Bull (Beijing)},
	year = {2024},
	abstract = {Fusobacterium nucleatum (F. nucleatum), an oral anaerobe, is prevalent in colorectal cancer and is closely related to increased cancer cell growth, metastasis, and poor treatment outcomes. Bacterial vaccines capable of selectively eliminating bacteria present a promising approach to targeting intratumor F. nucleatum, thereby enhancing cancer treatment. Although adjuvants have been employed to enhance the immune response, the vaccine's effectiveness is constrained by inadequate T-cell activation necessary for eradicating intracellular pathogens. In this study, we developed a minimalistic, biomimetic nanovaccine by integrating highly immunostimulatory adjuvant cholesterol-modified CpG oligonucleotides into the autologously derived F. nucleatum membranes. Compared to the traditional vaccines consisting of inactivated bacteria and Alum adjuvant, the nanovaccine coupled with bacterial membranes and adjuvants could remarkably improve multiple antigens and adjuvant co-delivery to dendritic cells, maximizing their ability to achieve effective antigen presentation and strong downstream immune progress. Notably, the nanovaccine exhibits outstanding selective prophylactic and therapeutic effects, eliminating F. nucleatum without affecting intratumoral and gut microbiota. It significantly enhances chemotherapy efficacy and reduces cancer metastasis in F. nucleatum-infected colorectal cancer. Overall, this work represents the rational application of bacterial nanovaccine and provides a blueprint for future development in enhancing the antitumor effect against bacterial-infected cancer.},
	doi = {10.1016/j.scib.2024.06.016},
	pmid = {38918142 [Indexed for MEDLINE]}
}

@ARTICLE{10.1093/lambio/ovae049,
	author = {Boyanova L and Medeiros J and Yordanov D and Gergova R and Markovska R},
	title = {Turmeric and curcumin as adjuncts in controlling Helicobacter pylori-associated diseases: a narrative review.},
	journal = {Lett Appl Microbiol},
	year = {2024},
	abstract = {Non-antibiotic adjuncts may improve Helicobacter pylori infection control. Our aim was to emphasize curcumin benefits in controlling H. pylori infection. We discussed publications in English mostly published since 2020 using keyword search. Curcumin is the main bioactive substance in turmeric. Curcumin inhibited H. pylori growth, urease activity, three cag genes, and biofilms through dose- and strain-dependent activities. Curcumin also displayed numerous anticancer activities such as apoptosis induction, anti-inflammatory and anti-angiogenic effects, caspase-3 upregulation, Bax protein enhancement, p53 gene activation, and chemosensitization. Supplementing triple regimens, the agent increased H. pylori eradication success in three Iranian studies. Bioavailability was improved by liposomal preparations, lipid conjugates, electrospray-encapsulation, and nano-complexation with proteins. The agent was safe at doses of 0.5->4 g daily, the most common (in 16% of the users) adverse effect being gastrointestinal upset. Notably, curcumin favorably influences the intestinal microbiota and inhibits Clostridioides difficile. Previous reports showed the inhibitory effect of curcumin on H pylori growth. Curcumin may become an additive in the therapy of H. pylori infection, an adjunct for gastric cancer control, and an agent beneficial to the intestinal microbiota. Further examination is necessary to determine its optimal dosage, synergy with antibiotics, supplementation to various eradication regimens, and prophylactic potential.},
	doi = {10.1093/lambio/ovae049},
	pmid = {38794899 [Indexed for MEDLINE]}
}

